from pymodbus.client import ModbusTcpClient
import struct

client = ModbusTcpClient('192.168.1.100', port=502)
client.connect()
# 假设PLC中有一个ANY指针变量存储在DB10的偏移0处，其内部结构为：
# 数据类型(2字节) + 长度(2字节) + 地址(4字节) + 保留(2字节)
